[[module CSS]]

@import url('https://fonts.bunny.net/css?family=Pinyon+Script');

@import url('https://fonts.bunny.net/css?family=Cinzel');



:root { --body-font: 'Noto Sans Cuneiform', 'Inter', 'Arial', sans-serif;

  --header-height: clamp(10rem,55vmin,30rem);

  --header-image: url("https://scp-wiki.wdfiles.com/local--files/bleep-s-onyx-proposal/Bleep%20Banner");

  --footer-image: url("https://scp-wiki.wdfiles.com/local--files/bleep-s-onyx-proposal/Bleep%20Banner");

}



#footer, #extrac-div-1, #extrac-div-1 span {

    background-image: var(--footer-image);

    background-size: 100vmax;

    background-attachment: fixed;

    background-position: bottom;

    height: clamp(10rem,55vmin,50rem);

    background-repeat: no-repeat;

}



#extra-div-1 {

    background-position: top;

}



.storybook {

   font-family:Philosopher;

   font-weight: 400;

   font-style: normal;

   background-image: url( http://scp-wiki.wikidot.com/local--files/scp-8166/paper-min%5B1%5D.png);

   font-size: 120%;

   box-sizing: border-box;

   border: 2vw solid rgba(0,0,0,0.5);

   border-image: url('https://scp-wiki.wikidot.com/local--files/bleep-s-onyx-proposal/wl_border.webp') 600 round;

   border-image-width: 6;

   padding: 0.5vw;

   outline: 2px solid purple;

}





.danke {

    padding: 5px;

    font-family: monospace;

    font-size: 1.1em;

    margin: 1.5em;

}



.Moose {

    background-color:#010a01;

    border: 3px solid #b695b3;

    color: #CF9FFF;

}



.containercontainer {

position: relative;width: auto;height: auto;border: 2px solid #666;background: #141212;color: #3F3;margin-top: 1em;margin-bottom: 1em;

}



.containercontainer .container .overlay {

background: rgba(51, 255, 51, 0.9);color: #121010;position: absolute;width: auto;height: 50px;top: 0;right: 0;bottom: 0;left: 0;margin: auto;line-height: 50px;display: inline;vertical-align: middle;font-family: Courier New;font-size: 30px;letter-spacing: 5px;font-weight: bolder;z-index: 3;animation: overlay-anim 10s linear;animation-fill-mode: forwards;animation-iteration-count: infinite;

}



.overlayback {

background: rgba(187, 187, 187, 0.5);z-index: 3;position: absolute;top: 0;left: 0;bottom: 0;right: 0;width: auto;height: auto;animation: overlay-anim 10s linear;animation-fill-mode: forwards;animation-iteration-count: infinite;

}



.containercontainer .container {width: inherit;height: inherit;position: relative;overflow: hidden;

}



.containercontainer .container::after {

content: " ";display: block;position: absolute;top: 0;left: 0;bottom: 0;right: 0;background: rgba(21, 19, 19, 0.2);opacity: 0;z-index: 2;

}



.containercontainer .container::before {

content: " ";display: block;position: absolute;top: 0;left: 0;bottom: 0;right: 0;background: linear-gradient(rgba(18, 16, 16, 0.03) 50%, rgba(0, 0, 0, 0.45) 50%), linear-gradient(90deg, rgba(255, 0, 0, 0.22), rgba(0, 255, 0, 0.11), rgba(0, 0, 255, 0.22));z-index: 2;background-size: 100% 2px, 3px 100%;

}



.container h1,.container h2,.container h3,.container h5,.container h6 {

color: #3F3;}.container hr {border-top: 1px dotted #3F3;border-bottom: none;

}



.container hr {

border-top: 1px solid #3F3;border-bottom: 1px solid #3F3;color: transparent;background-color: transparent;

}



.container hr:after {

display: block;margin-top: 2px;border-top: 1px solid #3F3;border-bottom: 1px solid #3F3;

}



.blinkbar {

animation: blink 5s infinite; letter-spacing: -0.13em;

}



@keyframes blink{to{opacity: .0;}}@keyframes overlay-anim {0% {visibility: hidden; }10% {visibility: hidden; }11% {visibility: visible; }50% {visibility: hidden; }100% {visibility: hidden; }}



.anchor {

    position: sticky;

    height:0;

    top: 0;

}



.sidebox {

    padding: .2rem;

    margin-top: 0;

    margin-bottom: 8px;

    margin: 0.5rem;

    width: calc((100vw - 60.25rem)/2);

    max-width: max-content;

    max-height: calc(100vh - 6rem);

    position: absolute;

    top: 0;

    left: 100%;

    z-index: 5;

    overflow: auto;

    box-sizing: border-box;

    border: 0.25vw solid rgba(24,49,70,0.8);

}





@media (max-width: 1200px) {

.sidebox {

display: none;

}

}



.gridTOC {

    display: none;

    grid-template-columns: repeat(2, 1fr);

    gap: 0.4em;

    text-align: center;

    width: max-content;

    margin: auto;

}



.gridTOC p {

    margin-block-start: 0;

    margin-block-end: 0;

}



.gridTOC a {

    display: block;

    width: 100%;

    color: #10aead;

    transition: 200ms;

}



.gridTOCspec, .gridTOCdesc {

    background-color: #f2fafd;

}



.gridTOChead {

    grid-column: 1 / 3;

    grid-row: 1 / 2;

    text-decoration: underline;

    font-weight: bold;

}



.gridTOCspec {

    grid-column: 1 / 2;

    grid-row: 2 / 3;

    border-left: solid 4px #0eadac;

}



.gridTOCspec a {

    padding: 0 5px;

}



.gridTOCdesc {

    grid-column: 2 / 3;

    grid-row: 2 / 3;

    align-content: center;

    justify-items: stretch;

}



.gridTOCadd1, .gridTOCadd2, .gridTOCadd3 {

    background-color: #f2fafd;

    border-left: solid 4px #0eadac;

    display: flex;

    justify-content: center;

    align-items: center;

}



.gridTOCadd1 {

    grid-column: 1 / 2;

    grid-row: 3 / 4;

}



.gridTOCadd2 {

    grid-column: 1 / 2;

    grid-row: 5 / 7;

}



.gridTOCadd3 {

    grid-column: 1 / 2;

    grid-row: 7 / 12;

}



.gridTOCnum1, .gridTOCnum2, .gridTOCnum3 {

    display: flex;

    flex-wrap: wrap;

    justify-content: center;

}



.gridTOCnum1 {

    grid-column: 2 / 3;

    grid-row: 3 / 4;

}



.gridTOCnum2 {

    grid-column: 2 / 3;

    grid-row: 5 / 7;

}



.gridTOCnum3 {

    grid-column: 2 / 3;

    grid-row: 7 / 12;

}



.gridTOCnumb {

    background-color: #f2fafd;

    flex-basis: 30%;

    margin: 0.1em;

}



.gridTOC a:hover {

    color: #f2fafd;

    background-color: #10aead;

    text-decoration: none;

}



.gridTOCtops {

    grid-column: 1 / 3;

    grid-row: 4 / 5;

    background-color: #142f46;

    color: #f2fafd;

}



@media (max-width: 1200px) {

.gridTOC {

    display: grid;

}

}



.document {

    background-color: #edf8ff;

    padding: 1em;

    margin: 2em auto;

    border: solid 1px #ccc;

    border-right: 5px solid #3875a1;

    border-left: 5px solid #3875a1;

}



petitions, div.petitions {

    background-color: rgb(var(--hazy-sky));

    border: none;

    border-top: solid 0.25rem rgb(var(--lagoon-hue));

    padding: 0.25rem 1.125rem;

}



factuals, div.factual {

    background-color: rgb(var(--hazy-sky));

    border: none;

    border-bottom: solid 0.25rem rgb(var(--lagoon-hue));

    padding: 0.25rem 1.125rem;

}



notes, div.notes {

    background-color: rgb(var(--hazy-sky));

    border: none;

    border-right: solid 0.25rem rgb(var(--lagoon-hue));

    padding: 0.25rem 1.125rem;

}



report, div.report {

    background-color: rgb(var(--hazy-sky));

    border: solid 0.25rem rgb(var(--lagoon-hue));

    padding: 0.25rem 1.125rem;

}



.document .oceansail {

    background-color: #990036;

    text-align: center;

    padding: 0.5em;

    margin: 0.45rem 0;

    font-size: 0.875em;

}



.document .oceansail h1 {

    color: #FFF;

    margin: 0;

    line-height: 1.05;

}



.act {

    font-family: Grenze Gotisch;

    color: #0A0A0A;

    font-size: 8rem;

    text-align: center;

    text-decoration: underline 6px #735600;

    margin-bottom: -17rem;

    text-shadow: 4px 4px 4px #735600;

}



.sub {

    font-family: Grenze Gotisch;

    color: #0A0A0A;

    font-size: 500%;

    text-align: center;

    text-shadow: 4px 4px 4px #735600;

}



.sub2 {

    font-family: Cinzel;

    color: #0A0A0A;

    font-size: 300%;

    text-align: center;

    text-shadow: 4px 4px 4px #735600;

}



.scenesetter {

    padding-inline: 1.75rem;

    position: relative;

    padding-block: 1.25rem;

    isolation: isolate;

}



.scenesetter::before {

    content: "";

    position: absolute;

    top: 0; left: 0;

    width: 100%; height: 100%;

    background-image: var(--header-image);

    background-size: cover;

    background-position: center;

    opacity: 0.195;

    box-shadow: inset 0 0 4rem 3.25rem rgb(var(--foamy-white));

    filter: blur(1.375rem);

    z-index: -1;



.mither {

    font-family: var(--header-font);

    color: green;

    font-size: 1.375em;

    line-height: 1.275;

}



.mither p { line-height: inherit; }



.ultraspace {

    padding-block: 3.5rem;

}



